mapper.select:
SELECT ps.* FROM product_snapshot ps LEFT JOIN product_operation_state pos ON ps.activity_id = pos.activity_id AND ps.product_id = pos.product_id AND pos.deleted = 0 WHERE ps.activity_id = #{activityId} AND ps.deleted = 0
AND ps.status = #{promotionStatus}
AND ( ps.title LIKE CONCAT('%', #{productInfo}, '%') OR ps.product_id LIKE CONCAT('%', #{productInfo}, '%') OR ps.shop_name LIKE CONCAT('%', #{productInfo}, '%') )
AND ps.product_id IN
#{id}
AND ( ps.product_id IN
#{id}
OR ps.product_id NOT IN
#{id}
)
AND ps.product_id IN
#{id}
AND ps.product_id NOT IN
#{id}
AND ps.product_id IN
#{id}
ORDER BY CASE WHEN pos.pinned_until IS NOT NULL AND pos.pinned_until > #{now} AND pos.deleted = 0 THEN 0 ELSE 1 END ASC, CASE WHEN (pos.promote_link IS NOT NULL AND TRIM(pos.promote_link) <> '') OR (pos.short_link IS NOT NULL AND TRIM(pos.short_link) <> '') THEN 0 ELSE 1 END ASC, ps.activity_cos_ratio DESC NULLS LAST, ps.sync_time DESC NULLS LAST LIMIT #{limit} OFFSET #{offset}
